func solve(s string) []string {
    segments := []string{}
    seen := make(map[string]bool)
    n := len(s)
    i := 0
    for i < n {
        currentSegment := ""
        j := i
        for j < n {
            currentSegment += string(s[j])
            if !seen[currentSegment] {
                seen[currentSegment] = true
                segments = append(segments, currentSegment)
                i = j + 1
                break
            }
            j++
        }
        if j == n {
            segments = append(segments, currentSegment)
            seen[currentSegment] = true
            i = j + 1
        }
    }
    return segments
}
